## Objective

Add comprehensive tests for the new countdown timer, progress bar, warning phases, timeout expiration, and screen reader announcements in `ToolApproval`.

## Implementation

**File:** `apps/client/src/layers/features/chat/__tests__/ToolApproval.test.tsx`

Add the following test cases to the existing test file. The file already has the mock setup for `useTransport` and `ToolArgumentsDisplay`. All new tests go inside the existing `describe('ToolApproval', () => { ... })` block.

### Timer setup

Add `beforeEach` and `afterEach` for fake timers in a new `describe` block:

```typescript
describe('countdown timer', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('renders progress bar when timeoutMs is provided', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    const progressBar = screen.getByRole('progressbar');
    expect(progressBar).toBeDefined();
    expect(progressBar.getAttribute('aria-valuemax')).toBe('600');
    expect(progressBar.getAttribute('aria-valuenow')).toBe('600');
  });

  it('does not render progress bar when timeoutMs is undefined', () => {
    render(<ToolApproval {...baseProps} />);
    expect(screen.queryByRole('progressbar')).toBeNull();
  });

  it('does not show text countdown before warning threshold', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    // Advance to 5 minutes (5 minutes remaining — still in normal phase)
    vi.advanceTimersByTime(300_000);
    expect(screen.queryByText(/remaining/)).toBeNull();
  });

  it('shows text countdown at warning threshold (2 minutes remaining)', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    // Advance to 8 minutes (2 minutes remaining)
    vi.advanceTimersByTime(480_000);
    expect(screen.getByText(/remaining/)).toBeDefined();
  });

  it('shows countdown with correct format at 1:30 remaining', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    // Advance to 8 minutes 30 seconds (1:30 remaining)
    vi.advanceTimersByTime(510_000);
    expect(screen.getByText('1:30 remaining')).toBeDefined();
  });

  it('applies urgent styling at 1 minute remaining', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    // Advance to 9 minutes (1 minute remaining)
    vi.advanceTimersByTime(540_000);
    const countdownEl = screen.getByText(/remaining/);
    expect(countdownEl.className).toContain('text-status-error');
  });

  it('transitions to denied state when timeout expires', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    // Advance full 10 minutes
    vi.advanceTimersByTime(600_000);
    expect(screen.getByText(/Auto-denied/)).toBeDefined();
    expect(screen.getByText(/timed out after 10 minutes/)).toBeDefined();
    expect(screen.getByTestId('tool-approval-decided')).toBeDefined();
    expect(screen.getByTestId('tool-approval-decided').getAttribute('data-decision')).toBe('denied');
  });

  it('does not show timeout message on manual deny', async () => {
    const ref = createRef<ToolApprovalHandle>();
    render(<ToolApproval {...baseProps} ref={ref} timeoutMs={600_000} />);

    // Deny manually at 5 minutes
    vi.advanceTimersByTime(300_000);
    ref.current!.deny();

    await waitFor(() => {
      expect(screen.getByText('Denied')).toBeDefined();
    });
    expect(screen.queryByText(/Auto-denied/)).toBeNull();
    expect(screen.queryByText(/timed out/)).toBeNull();
  });

  it('approve works during countdown and stops timer display', async () => {
    const ref = createRef<ToolApprovalHandle>();
    render(<ToolApproval {...baseProps} ref={ref} timeoutMs={600_000} />);

    // Approve at 5 minutes
    vi.advanceTimersByTime(300_000);
    ref.current!.approve();

    await waitFor(() => {
      expect(screen.getByText('Approved')).toBeDefined();
    });
    // No progress bar in decided state
    expect(screen.queryByRole('progressbar')).toBeNull();
    // No timeout message
    expect(screen.queryByText(/Auto-denied/)).toBeNull();
  });

  it('announces at warning threshold for screen readers', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    vi.advanceTimersByTime(480_000); // 2 minutes remaining
    const liveRegion = screen.getByRole('status');
    expect(liveRegion.textContent).toBe('Tool approval required. 2 minutes remaining.');
  });

  it('announces at urgent threshold for screen readers', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    vi.advanceTimersByTime(540_000); // 1 minute remaining
    const liveRegion = screen.getByRole('status');
    expect(liveRegion.textContent).toBe('Urgent: 1 minute to approve or deny.');
  });

  it('announces at timeout expiry for screen readers', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    vi.advanceTimersByTime(600_000); // 0 seconds
    // The component transitions to decided state, but the announcement should have fired
    // We check the decided state instead since the live region is in the pending render
    expect(screen.getByText(/Auto-denied/)).toBeDefined();
  });

  it('updates aria-valuenow as time passes', () => {
    render(<ToolApproval {...baseProps} timeoutMs={600_000} />);
    vi.advanceTimersByTime(60_000); // 1 minute elapsed
    const progressBar = screen.getByRole('progressbar');
    expect(progressBar.getAttribute('aria-valuenow')).toBe('540');
  });
});
```

### Important Notes

- `vi.useFakeTimers()` intercepts `Date.now()`, `setInterval`, `setTimeout` so the countdown logic works deterministically
- `vi.advanceTimersByTime(ms)` advances all timers and fires any pending intervals
- The existing tests in the file do NOT use fake timers, so the new `describe` block manages its own timer lifecycle
- The mock for `useTransport` at the top of the file already handles the `approveTool`/`denyTool` calls needed by the approve/deny tests

## Verification

- Run `pnpm vitest run apps/client/src/layers/features/chat/__tests__/ToolApproval.test.tsx`
- All existing tests continue to pass
- All new countdown tests pass
- Run full test suite: `pnpm test -- --run`
